--- 方块小游戏->控制正在移动的方块

---@class LBlockMiniGameShape
local LBlockMiniGameShape = LxClass("LBlockMiniGameShape", nil)

-----------------------------------------------------------------
local Input = UnityEngine.Input
local KeyCode = UnityEngine.KeyCode
local Vector3 = Vector3
local Time = Time
local NameToIndex = { ["1"] = 1, ["2"] = 2, ["3"] = 3, ["4"] = 4 }
local NameToIndex2 = { ["1_1"] = 1, ["2_1"] = 2, ["3_1"] = 3, ["4_1"] = 4 }

-- 开始位置
local StartPosList = {
	[1] = Vector3(0, 0, 0),
	[2] = Vector3(1, -2, 0),
	[3] = Vector3(1, -2, 0),
	[4] = Vector3(0, -1, 0),
	[5] = Vector3(1, -1, 0),
	[6] = Vector3(1, -2, 0),
	[7] = Vector3(1, -2, 0),
}

-- 准备位置
local ReadyPosList = {
	[1] = Vector3(7.64, -4.28, 0),
	[2] = Vector3(8.22, -4.93, 0),
	[3] = Vector3(8.22, -4.93, 0),
	[4] = Vector3(7.92, -4.44, 0),
	[5] = Vector3(8.22, -4.5, 0),
	[6] = Vector3(8.22, -4.93, 0),
	[7] = Vector3(8.22, -4.93, 0),
}

local StartScale = Vector3(1, 1, 1)
local ReadyScale = Vector3(0.5, 0.5, 0.5)

-----------------------------------------------------------------
function LBlockMiniGameShape:LBlockMiniGameShape()
	-- 方块的gameobject
	self._obj = nil

	-- 方块的transform
	self._trans = nil
	self._trans2 = nil

	-- 方块的配置文件
	self._ref = nil

	-- 方块的移动一格的间隔
	self._interval = 0

	-- 下划加速的下落时间
	self._speedUpInterval = 0

	-- 一格的累计时间
	self._deltaTime = 0

	-- 加速
	self._isSpeedUp = false

	-- LBlockMiniGameMap
	self._map = nil

	-- 4个小方块组成的方块的小方块列表
	self._blockList = {}
	self._blockList2 = {}

	-- 方块的旋转中心点
	self._pivotTrans = nil

	-- 精灵
	self._spineMap = nil

	-- 编辑器模式
	self.isEditor = UnityEngine.Application.isEditor

	-- gModelBlockMiniGame
	self._model = gModelBlockMiniGame

	-- 锁定
	self._lock = false
end

-- 初始化
function LBlockMiniGameShape:Init(param)
	self._obj = param.obj
	self._trans = self._obj.transform
	self._ref = param.ref
	self._interval = 1000 / param.speed
	self._map = param.map
	self._trans:SetParent(param.parent, false)

	self._pivotTrans = CS.FindTrans(self._obj, "Pivot")
	self:InitBlockList()
	self:InitSpine()
end

function LBlockMiniGameShape:Destroy()
	for k, v in pairs(self._spineMap) do
		v:Destroy()
	end
	self._spineMap = {}
end

-- 开始位置
function LBlockMiniGameShape:InitStartPos()
	self._trans.localPosition = StartPosList[self._ref.type]
	self._trans.localScale = StartScale

	self._map:SetEmptyShapePos(self)
end

-- 准备位置
function LBlockMiniGameShape:InitReadyPos()
	self._trans.localPosition = ReadyPosList[self._ref.type]
	self._trans.localScale = ReadyScale

	self:ShowEmptyBlock(false)
end

-- 初始化小方块列表
function LBlockMiniGameShape:InitBlockList()
	local list = {}
	local list2 = {}
	local trans = self._trans
	for i = 1, trans.childCount do
		local child = trans:GetChild(i - 1)
		local name = child.name
		if NameToIndex[name] then
			list[NameToIndex[name]] = child
		elseif NameToIndex2[name] then
			list2[NameToIndex2[name]] = child
		end
	end
	self._blockList = list
	self._blockList2 = list2
end

-- 获取小方块列表
function LBlockMiniGameShape:GetBlockList()
	return self._blockList
end

-- 获取小方块列表
function LBlockMiniGameShape:GetBlockList2()
	return self._blockList2
end

-- 显示隐藏空格子
function LBlockMiniGameShape:ShowEmptyBlock(isShow)
	for _, trans in ipairs(self._blockList2) do
		trans.gameObject:SetActive(isShow)
	end
end

-- 初始化精灵
function LBlockMiniGameShape:InitSpine()
	self._spineMap = {}
	local model = self._model
	for index, trans in ipairs(self._blockList) do
		local monsterRefId = self:GetMonsterRefId(index)
		if monsterRefId then
			local mosterRef = model:GetMonsterRef(monsterRefId)
			local heroEffectRef = model:GetHeroEffectRef(monsterRefId)
			local dp = LDisplaySpine:New()
			dp:CreateSpine(trans, heroEffectRef.prefabName)
			dp:SetScale(mosterRef.scale)
			dp:SetLoadedFunction(function()
				self:OnLoadedSpine(dp, mosterRef)
			end)
			dp:StartLoad()

			self._spineMap[index] = dp
		end
	end
end

-- 加载精灵完成
function LBlockMiniGameShape:OnLoadedSpine(dp, mosterRef)
	local trans = dp:GetDisplayTrans()
	local tab = string.split(mosterRef, ",")
	local x = tonumber(tab[1]) or 0
	local y = tonumber(tab[2]) or 0
	trans.localPosition = Vector3(x, y, 0)  
	self:ResetSpineRotation({ ["1"] = dp })
end

-- 重置精灵旋转
function LBlockMiniGameShape:ResetSpineRotation(map)
	local map = map or self._spineMap
	local identity = Quaternion.identity
	for _, dp in pairs(map) do
		local trans = dp:GetDisplayTrans()
		if trans then
			trans.rotation = identity
		end
	end
end

-- 获取小方块上怪物id, 返回nil表示没有怪物
function LBlockMiniGameShape:GetMonsterRefId(blockIndex)
	local id = self._ref["block" .. blockIndex]
	if id and id > 0 then
		return id
	end
	return nil
end

-- 弹出怪物dp
function LBlockMiniGameShape:PopSpine(blockIndex)
	local dp = self._spineMap[blockIndex]
	self._spineMap[blockIndex] = nil
	return dp
end

-- update
function LBlockMiniGameShape:Update()
	-- if self._isSpeedUp then
	-- 	self:Fall(4)
	-- else
	self._deltaTime = self._deltaTime + Time.deltaTime

	if self._deltaTime >= self._interval then
		self._deltaTime = 0
		self:LimitFall(1)
	end
	-- end

	self:InputEditor()
end

-- true:表示变化中
function LBlockMiniGameShape:IsChanging()
	return self._isChangeing
end

-- 限制下落
function LBlockMiniGameShape:LimitFall(step)
	if self:IsChanging() then return end

	self._isChangeing = true
	self:Fall(step)
	self._isChangeing = nil
end

-- 下落
function LBlockMiniGameShape:Fall(step)
	local trans = self._trans
	local pos = trans.localPosition
	pos.y = pos.y - step
	trans.localPosition = pos

	local map = self._map
	if map:IsShapePosValid(self) then
		map:PlayDropAudio()
		map:SetEmptyShapePos(self)
		return
	end

	for i = 1, step do
		pos.y = pos.y + 1
		trans.localPosition = pos
		if map:IsShapePosValid(self) then
			break
		end
	end

	if self._moveLeft == true then
		self._moveLeft = nil
		self._isChangeing = nil
		self:StepLeft()
		return
	elseif self._moveLeft == false then
		self._isChangeing = nil
		self:StepRight()
		self._moveLeft = nil
		return
	end

	map:FallEnd(self)
	self:ShowEmptyBlock(false)
end

-- 左移
function LBlockMiniGameShape:StepLeft()
	if self:IsChanging() then return end

	self._isChangeing = true

	local trans = self._trans
	local pos = trans.localPosition
	pos.x = pos.x - 1
	trans.localPosition = pos
	local map = self._map
	if map:IsShapePosValid(self) then
		map:PlayControlAudio()
		map:SetEmptyShapePos(self)
		self._isChangeing = nil
		return
	end

	pos.x = pos.x + 1
	trans.localPosition = pos
	self._isChangeing = nil
end

-- 右移
function LBlockMiniGameShape:StepRight()
	if self:IsChanging() then return end

	self._isChangeing = true

	local trans = self._trans
	local pos = trans.localPosition
	pos.x = pos.x + 1
	trans.localPosition = pos
	local map = self._map
	if map:IsShapePosValid(self) then
		map:PlayControlAudio()
		map:SetEmptyShapePos(self)
		self._isChangeing = nil
		return
	end

	pos.x = pos.x - 1
	trans.localPosition = pos
	self._isChangeing = nil
end

-- 加速
function LBlockMiniGameShape:SpeedUp(moveLeft)
	if self._isSpeedUp then return end

	self._interval = self._speedUpInterval
	self._isSpeedUp = true
	self._moveLeft = moveLeft
	self._lock = moveLeft ~= nil
end

-- 旋转
function LBlockMiniGameShape:RotateShape()
	if self:IsChanging() then return end

	self._isChangeing = true

	local trans = self._trans
	trans:RotateAround(self._pivotTrans.position, Vector3.forward, -90)
	self:ResetSpineRotation()
	local map = self._map
	local can, offtX, offtY = map:CanShapeRotate(self)
	if can then
		if offtX ~= 0 or offtY ~= 0 then
			local pos = trans.localPosition
			pos.x = pos.x - offtX
			pos.y = pos.y - offtY
			trans.localPosition = pos
		end
		map:PlayControlAudio()
		map:SetEmptyShapePos(self)

		self._isChangeing = nil
		return
	end
	trans:RotateAround(self._pivotTrans.position, Vector3.forward, 90)
	self:ResetSpineRotation()

	self._isChangeing = nil
end

-- 是否锁定
function LBlockMiniGameShape:IsLock()
	return self._lock
end

-- 编辑器模式下调用
function LBlockMiniGameShape:InputEditor()
	if not self.isEditor then return end

	if Input.GetKeyDown(KeyCode.LeftArrow) then
		self:StepLeft()
	elseif Input.GetKeyDown(KeyCode.RightArrow) then
		self:StepRight()
	elseif Input.GetKeyDown(KeyCode.UpArrow) then
		self:RotateShape()
	elseif Input.GetKeyDown(KeyCode.DownArrow) then
		self:SpeedUp()
	end
end

return LBlockMiniGameShape
